class NotificationService {
  constructor() {
    this.notifications = [];
  }

  sendNotification(message, type = 'info') {
    const notification = {
      id: Date.now(),
      message,
      type,
      timestamp: new Date()
    };

    this.notifications.push(notification);
    return notification;
  }

  getNotifications() {
    return this.notifications;
  }

  clearNotifications() {
    this.notifications = [];
  }
}

module.exports = { NotificationService };
EOF

